 39→  try {
 40→    const res = await fetch(`${baseUrl}/api/config/llm`);
 41→    if (res.ok) {
 42→      const data = await res.json() as { provider?: string; model?: string };
 43→      if (!data.provider || !data.model) {
 44→        console.log(chalk.yellow('  LLM provider is not configured.'));
 45→        console.log(chalk.dim('  Configure it with: code-insights config llm'));
 46→        console.log();
