124→async function backfillBatch(
125→  baseUrl: string,
126→  sessionIds: string[],
127→  offset: number,
128→  total: number,
129→  signal?: AbortSignal
130→): Promise<{ completed: number; failed: number }> {
131→  const res = await fetch(`${baseUrl}/api/facets/backfill`, {
132→    method: 'POST',
133→    headers: { 'Content-Type': 'application/json' },
134→    // force=true so outdated sessions (which already have facets) are re-processed.
135→    // Missing sessions are unaffected — the guard only fires when a row exists.
136→    body: JSON.stringify({ sessionIds, force: true }),
137→    signal,
138→  });
139→
140→  if (!res.ok) {
141→    const text = await res.text().catch(() => res.statusText);
142→    throw new Error(`Server error ${res.status}: ${text}`);
143→  }
144→  if (!res.body) throw new Error('No response body');
145→
146→  const reader = res.body.pipeThrough(new TextDecoderStream()).getReader();
147→  let buffer = '';
148→  let currentEvent = '';
149→  let currentData = '';
150→  let result = { completed: 0, failed: 0 };
151→
152→  const spinner = ora({ text: `  Backfilling ${offset + 1}-${offset + sessionIds.length} of ${total}...`, indent: 2 }).start();
153→
154→  try {
155→    while (true) {
156→      const { done, value } = await reader.read();
157→      if (done) break;
158→      buffer += value;
159→      const lines = buffer.split('\n');
160→      buffer = lines.pop() ?? '';
161→      for (const line of lines) {
162→        if (line.startsWith('event: ')) {
163→          currentEvent = line.slice(7).trim();
164→        } else if (line.startsWith('data: ')) {
165→          currentData = line.slice(6);
166→        } else if (line === '' && currentEvent && currentData) {
167→          try {
168→            const data = JSON.parse(currentData) as Record<string, unknown>;
169→            if (currentEvent === 'progress') {
170→              const processed = (data.completed as number) + (data.failed as number);
171→              spinner.text = `  Backfilling ${offset + processed + 1} of ${total}...`;
172→            } else if (currentEvent === 'complete') {
173→              result = { completed: data.completed as number, failed: data.failed as number };
174→              spinner.succeed(`  Batch complete: ${result.completed} extracted, ${result.failed} failed`);
175→            }
176→          } catch { /* skip malformed */ }
177→          currentEvent = '';
178→          currentData = '';
179→        }
180→      }
181→    }
182→  } finally {
183→    reader.releaseLock();
184→  }
185→  return result;
186→}
