192→// Mirrors formatIsoWeek/parseIsoWeek in server/src/routes/shared-aggregation.ts
193→// -- kept here so the CLI doesn't import server code.
194→// IMPORTANT: keep in sync with the canonical server implementation.
195→function getCurrentIsoWeek(): string {
196→  const now = new Date();
197→  const nowDay = now.getUTCDay();
198→  const daysToMonday = nowDay === 0 ? 6 : nowDay - 1;
199→  const monday = new Date(now.getTime() - daysToMonday * 86400000);
200→
201→  const thursday = new Date(monday.getTime() + 3 * 86400000);
202→  const year = thursday.getUTCFullYear();
203→
204→  const jan4 = new Date(Date.UTC(year, 0, 4));
205→  const jan4Day = jan4.getUTCDay();
206→  const daysToW1Monday = jan4Day === 0 ? 6 : jan4Day - 1;
207→  const week1Monday = new Date(jan4.getTime() - daysToW1Monday * 86400000);
208→
209→  const weekNum = Math.round((monday.getTime() - week1Monday.getTime()) / (7 * 86400000)) + 1;
210→  return `${year}-W${String(weekNum).padStart(2, '0')}`;
211→}
212→
213→const ISO_WEEK_RE = /^(\d{4})-W(\d{2})$/;
214→
215→async function reflectAction(options: {
216→  section?: string;
217→  week?: string;
218→  project?: string;
219→}): Promise<void> {
220→  const baseUrl = getBaseUrl();
221→  const week = options.week || getCurrentIsoWeek();
222→
223→  // Validate --week format: must be YYYY-WNN with year 2020-2100 and week number 1-53
224→  if (options.week) {
225→    const match = ISO_WEEK_RE.exec(options.week);
226→    const year = match ? parseInt(match[1], 10) : 0;
227→    const weekNum = match ? parseInt(match[2], 10) : 0;
228→    if (!match || weekNum < 1 || weekNum > 53 || year < 2020 || year > 2100) {
229→      console.log(chalk.red('  Invalid week format: "' + options.week + '"'));
230→      console.log(chalk.dim('  Use YYYY-WNN format with year 2020-2100, e.g., 2026-W10'));
231→      console.log();
232→      process.exit(1);
233→    }
234→  }
235→
236→  await checkServer(baseUrl);
237→
238→  console.log(chalk.dim(`  Generating reflection for ${week}...`));
239→
240→  // Check minimum session threshold
241→  const checkParams = new URLSearchParams();
242→  checkParams.set('period', week);
243→  if (options.project) checkParams.set('project', options.project);
244→  const aggRes = await fetch(`${baseUrl}/api/facets/aggregated?${checkParams.toString()}`);
245→  if (aggRes.ok) {
246→    const agg = await aggRes.json() as { totalSessions: number; totalAllSessions: number };
247→    if (agg.totalSessions < 8) {
