 35→// Maximum tokens to send to LLM (leaving room for response)
 36→const MAX_INPUT_TOKENS = 80000;
 37→const ANALYSIS_VERSION = '3.0.0';
 38→
 39→export interface AnalysisProgress {
 40→  phase: 'loading_messages' | 'analyzing' | 'saving';
 41→  currentChunk?: number;
 42→  totalChunks?: number;
 43→}
 44→
 45→export interface AnalysisOptions {
 46→  onProgress?: (progress: AnalysisProgress) => void;
 47→  signal?: AbortSignal;
 48→}
 49→
 50→export interface AnalysisResult {
 51→  success: boolean;
 52→  insights: InsightRow[];
 53→  error?: string;
 54→  error_type?: string;
 55→  response_length?: number;
 56→  response_preview?: string;
 57→  usage?: {
 58→    inputTokens: number;
 59→    outputTokens: number;
 60→  };
 61→}
 62→
 63→// Re-export ParseError so routes can import it from analysis.ts
 64→export type { ParseError };
 65→
 66→// Shape of a saved insight row (matches the SQLite schema)
 67→export interface InsightRow {
 68→  id: string;
 69→  session_id: string;
 70→  project_id: string;
 71→  project_name: string;
 72→  type: string;
 73→  title: string;
 74→  content: string;
 75→  summary: string;
 76→  bullets: string;           // JSON-encoded string[]
 77→  confidence: number;
