286→/**
287→ * Analyze prompt quality for a session.
288→ */
289→export async function analyzePromptQuality(
290→  session: SessionData,
291→  messages: SQLiteMessageRow[],
292→  options?: AnalysisOptions
293→): Promise<AnalysisResult> {
294→  if (!isLLMConfigured()) {
295→    return {
296→      success: false,
297→      insights: [],
298→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
299→    };
300→  }
301→
302→  if (messages.length === 0) {
303→    return {
304→      success: false,
305→      insights: [],
306→      error: 'No messages found for this session.',
307→    };
308→  }
309→
310→  const userMessages = messages.filter(m => m.type === 'user');
311→  if (userMessages.length < 2) {
312→    return {
313→      success: false,
314→      insights: [],
315→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
316→    };
317→  }
318→
319→  try {
320→    const client = createLLMClient();
321→    const formattedMessages = formatMessagesForAnalysis(messages);
322→
323→    let analysisInput = formattedMessages;
324→    const estimatedTokens = client.estimateTokens(formattedMessages);
325→    if (estimatedTokens > MAX_INPUT_TOKENS) {
326→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
327→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
328→    }
329→
330→    const prompt = generatePromptQualityPrompt(
331→      session.project_name,
332→      analysisInput,
333→      messages.length
334→    );
335→
336→    options?.onProgress?.({ phase: 'analyzing' });
337→    const response = await client.chat([
338→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
339→      { role: 'user', content: prompt },
340→    ], { signal: options?.signal });
341→
342→    const parsed = parsePromptQualityResponse(response.content);
343→    if (!parsed.success) {
344→      return {
345→        success: false,
346→        insights: [],
347→        error: 'Failed to parse prompt quality analysis. Please try again.',
348→        error_type: parsed.error.error_type,
349→        response_length: parsed.error.response_length,
350→        response_preview: parsed.error.response_preview,
351→      };
352→    }
353→
354→    options?.onProgress?.({ phase: 'saving' });
355→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
356→
357→    // Save new insight, then delete old prompt_quality insights
358→    saveInsightsToDb([insight]);
359→    deleteSessionInsights(session.id, {
360→      includeOnlyTypes: ['prompt_quality'],
361→      excludeIds: [insight.id],
362→    });
363→
364→    return {
365→      success: true,
366→      insights: [insight],
367→      usage: response.usage ? {
368→        inputTokens: response.usage.inputTokens,
369→        outputTokens: response.usage.outputTokens,
370→      } : undefined,
371→    };
372→  } catch (error) {
373→    if (error instanceof Error && error.name === 'AbortError') {
374→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
375→    }
376→    return {
377→      success: false,
378→      insights: [],
379→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
380→      error_type: 'api_error',
381→    };
382→  }
383→}
