385→export interface RecurringInsightGroup {
386→  insightIds: string[];
387→  theme: string;
388→}
389→
390→export interface RecurringInsightResult {
391→  success: boolean;
392→  groups: RecurringInsightGroup[];
393→  updatedCount: number;
394→  error?: string;
395→  usage?: {
396→    inputTokens: number;
397→    outputTokens: number;
398→  };
399→}
