721→function convertPromptQualityToInsightRow(response: PromptQualityResponse, session: SessionData): InsightRow {
722→  const now = new Date().toISOString();
723→
724→  // Normalize categories at write time (mirrors saveFacetsToDb pattern)
725→  const normalizedFindings = response.findings.map(f => ({
726→    ...f,
727→    category: f.category ? normalizePromptQualityCategory(f.category) : 'uncategorized',
728→  }));
729→
730→  const normalizedTakeaways = response.takeaways.map(t => ({
