806→/**
807→ * Delete insights for a session, with optional type and ID exclusions.
808→ */
809→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
810→  const db = getDb();
811→  const conditions: string[] = ['session_id = ?'];
812→  const params: (string | number)[] = [sessionId];
813→
814→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
815→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
816→    params.push(...opts.excludeTypes);
817→  }
818→
819→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
820→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
821→    params.push(...opts.includeOnlyTypes);
822→  }
823→
824→  if (opts.excludeIds && opts.excludeIds.length > 0) {
825→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
826→    params.push(...opts.excludeIds);
827→  }
828→
829→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
