144→/**
145→ * Run all aggregation queries needed for facet analysis and synthesis.
146→ * Aggregation is done in code (SQL), not by LLMs — LLMs synthesize, they don't count.
147→ *
148→ * project and source are passed separately so streak can build its own
149→ * period-free where clause (streak measures continuity across all time).
150→ */
151→export function getAggregatedData(
152→  db: ReturnType<typeof getDb>,
153→  where: string,
154→  params: (string | number)[],
155→  project?: string,
156→  source?: string
157→): AggregatedData {
158→  const hasWhere = where.length > 0;
159→  const extraPrefix = hasWhere ? 'AND' : 'WHERE';
160→
161→  const frictionCategories = db.prepare(`
162→    SELECT
163→      json_extract(je.value, '$.category') as category,
164→      COUNT(*) as count,
165→      AVG(CASE
166→        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
167→        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
168→        ELSE 1
169→      END) as avg_severity,
170→      json_group_array(json_extract(je.value, '$.description')) as examples,
171→      json_group_array(sf.session_id) as session_ids
172→    FROM session_facets sf
173→    JOIN sessions s ON sf.session_id = s.id
174→    CROSS JOIN json_each(sf.friction_points) je
175→    ${where}
176→    GROUP BY category
177→    ORDER BY count DESC, avg_severity DESC
178→  `).all(...params) as Array<{ category: string; count: number; avg_severity: number; examples: string; session_ids: string }>;
179→
180→  // Fetch effective patterns with confidence >= 50.
181→  // Category-based grouping happens in code (post-query) after normalizePatternCategory()
182→  // to handle any LLM variants that were stored before normalization was applied at write time.
183→  // extraPrefix handles the case where where is '' (tests pass empty string) vs a WHERE clause.
184→  const effectivePatternsRaw = db.prepare(`
185→    SELECT
186→      json_extract(je.value, '$.category') as category,
187→      json_extract(je.value, '$.description') as description,
188→      json_extract(je.value, '$.confidence') as confidence,
189→      json_extract(je.value, '$.driver') as driver
190→    FROM session_facets sf
191→    JOIN sessions s ON sf.session_id = s.id
192→    CROSS JOIN json_each(sf.effective_patterns) je
193→    ${where}
194→    ${extraPrefix} json_extract(je.value, '$.confidence') >= 50
195→    ORDER BY json_extract(je.value, '$.confidence') DESC
196→  `).all(...params) as Array<{ category: string | null; description: string | null; confidence: number | null; driver: string | null }>;
197→
198→  const outcomeDistribution = db.prepare(`
199→    SELECT outcome_satisfaction, COUNT(*) as count
200→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
201→    ${where}
202→    GROUP BY outcome_satisfaction
203→  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;
204→
205→  const workflowDistribution = db.prepare(`
206→    SELECT workflow_pattern, COUNT(*) as count
207→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
208→    ${where}
209→    ${extraPrefix} sf.workflow_pattern IS NOT NULL
210→    GROUP BY workflow_pattern
211→  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;
212→
213→  const characterDistribution = db.prepare(`
214→    SELECT session_character, COUNT(*) as count
215→    FROM sessions s
216→    ${where}
217→    ${extraPrefix} s.session_character IS NOT NULL
218→    GROUP BY session_character
219→  `).all(...params) as Array<{ session_character: string; count: number }>;
220→
221→  const totalRow = db.prepare(
222→    `SELECT COUNT(*) as count FROM session_facets sf JOIN sessions s ON sf.session_id = s.id ${where}`
223→  ).get(...params) as { count: number };
224→
225→  const totalAllRow = db.prepare(
226→    `SELECT COUNT(*) as count FROM sessions s ${where}`
227→  ).get(...params) as { count: number };
228→
229→  // Parse examples and session_ids from json_group_array output, then normalize via alias + Levenshtein clustering
230→  const parsedFriction = frictionCategories.map(fc => ({
231→    ...fc,
232→    examples: JSON.parse(fc.examples) as string[],
233→    session_ids: JSON.parse(fc.session_ids) as string[],
234→  }));
235→
236→  const normalizedFriction = new Map<string, { count: number; total_severity: number; examples: string[]; session_ids: string[] }>();
237→  for (const fc of parsedFriction) {
238→    const normalized = normalizeFrictionCategory(fc.category);
239→    const existing = normalizedFriction.get(normalized);
240→    if (existing) {
241→      existing.count += fc.count;
242→      existing.total_severity += fc.avg_severity * fc.count;
243→      existing.examples.push(...fc.examples);
244→      existing.session_ids.push(...fc.session_ids);
245→    } else {
246→      normalizedFriction.set(normalized, {
247→        count: fc.count,
248→        total_severity: fc.avg_severity * fc.count,
249→        examples: [...fc.examples],
250→        session_ids: [...fc.session_ids],
251→      });
252→    }
253→  }
254→
255→  // Partition: separate rate-limit-hit entries from general friction.
256→  // Rate limits are a billing/plan constraint — surfaced as a usage insight, not friction.
257→  // The alias map already normalizes all rate limit variants to "rate-limit-hit".
258→  // A regex sweep catches creative LLM variants ("throttled-by-api", etc.) that bypass
259→  // both the alias map and Levenshtein clustering.
260→  const RATE_LIMIT_CATEGORY = 'rate-limit-hit';
261→  const RATE_LIMIT_REGEX = /rate.?limit|throttl/i;
262→  let rateLimitInfo: RateLimitInfo | null = null;
263→
264→  // Accumulated data for rateLimitInfo, merged from exact match + regex sweep
265→  let rateLimitCount = 0;
266→  let rateLimitSessionIds: string[] = [];
267→  let rateLimitExamples: string[] = [];
268→
269→  const rateLimitEntry = normalizedFriction.get(RATE_LIMIT_CATEGORY);
270→  if (rateLimitEntry) {
271→    rateLimitCount += rateLimitEntry.count;
272→    rateLimitSessionIds.push(...rateLimitEntry.session_ids);
273→    rateLimitExamples.push(...rateLimitEntry.examples);
274→    normalizedFriction.delete(RATE_LIMIT_CATEGORY);
275→  }
276→
277→  // Regex sweep over remaining entries to catch variants the alias map missed
278→  for (const [category, entry] of normalizedFriction) {
279→    if (RATE_LIMIT_REGEX.test(category)) {
280→      rateLimitCount += entry.count;
281→      rateLimitSessionIds.push(...entry.session_ids);
282→      rateLimitExamples.push(...entry.examples);
283→      normalizedFriction.delete(category);
284→    }
285→  }
286→
287→  if (rateLimitCount > 0) {
288→    const uniqueSessions = new Set(rateLimitSessionIds);
289→    rateLimitInfo = {
290→      count: rateLimitCount,
291→      sessionsAffected: uniqueSessions.size,
292→      examples: rateLimitExamples.slice(0, 3),
293→    };
294→  }
295→
296→  const mergedFriction = Array.from(normalizedFriction.entries())
297→    .map(([category, data]) => ({
298→      category,
299→      count: data.count,
300→      avg_severity: data.total_severity / data.count,
301→      examples: data.examples.slice(0, 10),
302→    }))
303→    .sort((a, b) => b.count - a.count || b.avg_severity - a.avg_severity);
304→
305→  // frictionTotal reflects only non-rate-limit friction (rate limits partitioned separately)
306→  const frictionTotal = mergedFriction.reduce((sum, fc) => sum + fc.count, 0);
307→
308→  // Aggregate effective patterns by normalized category.
309→  // Each row from effectivePatternsRaw is a single pattern entry — we group by normalized
310→  // category in code so normalizePatternCategory() can handle LLM variants at query time.
311→  const normalizedPatterns = new Map<string, { total_confidence: number; count: number; descriptions: string[]; drivers: Record<string, number> }>();
312→  for (const row of effectivePatternsRaw) {
313→    // Skip entries with null category or description (malformed JSON in older sessions)
314→    if (!row.category || !row.description) continue;
315→    const normalized = normalizePatternCategory(row.category);
316→    const existing = normalizedPatterns.get(normalized);
317→    if (existing) {
318→      existing.count += 1;
319→      existing.total_confidence += row.confidence ?? 0;
320→      existing.descriptions.push(row.description);
321→      // Track driver breakdown — null/missing driver is silently skipped (transition period)
322→      if (row.driver) {
323→        existing.drivers[row.driver] = (existing.drivers[row.driver] ?? 0) + 1;
324→      }
325→    } else {
326→      const drivers: Record<string, number> = {};
327→      if (row.driver) {
328→        drivers[row.driver] = 1;
329→      }
330→      normalizedPatterns.set(normalized, {
331→        count: 1,
332→        total_confidence: row.confidence ?? 0,
333→        descriptions: [row.description],
334→        drivers,
335→      });
336→    }
337→  }
338→
339→  const effectivePatterns: AggregatedEffectivePattern[] = Array.from(normalizedPatterns.entries())
340→    .map(([category, data]) => ({
341→      category,
342→      label: getPatternCategoryLabel(category),
343→      frequency: data.count,
344→      avg_confidence: data.count > 0 ? data.total_confidence / data.count : 0,
345→      descriptions: data.descriptions.slice(0, 10),
346→      drivers: data.drivers,
347→    }))
348→    .sort((a, b) => b.frequency - a.frequency || b.avg_confidence - a.avg_confidence);
349→
350→  // Count distinct source tools within scope (for hero card stat pill)
351→  const sourceToolRow = db.prepare(
352→    `SELECT COUNT(DISTINCT source_tool) as count FROM sessions s ${where}`
353→  ).get(...params) as { count: number };
354→
355→  // Streak: count consecutive days (backward from today) with at least one session.
356→  // Always uses all-time scope — filtering by period would cap streak at the window size.
357→  // Respects project and source filters since those are user-scope constraints.
358→  const { where: streakWhere, params: streakParams } = buildWhereClause('all', project, source);
359→  const sessionDates = db.prepare(
360→    `SELECT DISTINCT date(started_at) as session_date FROM sessions s ${streakWhere} ORDER BY session_date DESC`
361→  ).all(...streakParams) as Array<{ session_date: string }>;
362→
363→  // Compare dates as YYYY-MM-DD strings in UTC to match SQLite's date() output.
364→  // Using toISOString().slice(0,10) avoids local timezone shifting the day boundary.
365→  const todayUTC = new Date().toISOString().slice(0, 10);
366→  const yesterdayUTC = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
367→
368→  let streak = 0;
369→  // baseline is the date we expect for the next streak entry.
370→  // Start at today; if first session is yesterday, reset baseline to yesterday so
371→  // the loop can continue counting backward from there correctly.
372→  let baseline: string | null = null;
373→
374→  for (const { session_date } of sessionDates) {
375→    if (baseline === null) {
376→      // First entry: must be today or yesterday to start an active streak
377→      if (session_date === todayUTC) {
378→        baseline = todayUTC;
379→      } else if (session_date === yesterdayUTC) {
380→        baseline = yesterdayUTC;
381→      } else {
382→        break; // Gap from today — no active streak
383→      }
384→      streak++;
385→    } else {
386→      // Subsequent entries: must be exactly one day before current baseline
387→      const prevDay: Date = new Date((baseline as string) + 'T00:00:00Z');
388→      prevDay.setUTCDate(prevDay.getUTCDate() - 1);
389→      const expectedPrev: string = prevDay.toISOString().slice(0, 10);
390→      if (session_date !== expectedPrev) break;
391→      baseline = expectedPrev;
392→      streak++;
393→    }
394→  }
395→
396→  return {
397→    frictionCategories: mergedFriction,
398→    effectivePatterns,
399→    outcomeDistribution: Object.fromEntries(outcomeDistribution.map(o => [o.outcome_satisfaction, o.count])),
400→    workflowDistribution: Object.fromEntries(workflowDistribution.map(w => [w.workflow_pattern, w.count])),
401→    characterDistribution: Object.fromEntries(characterDistribution.map(ch => [ch.session_character, ch.count])),
402→    totalSessions: totalRow.count,
403→    frictionTotal,
404→    totalAllSessions: totalAllRow.count,
405→    rateLimitInfo,
406→    streak,
407→    sourceToolCount: sourceToolRow.count,
408→  };
409→}
