351→      };
352→    }
353→
354→    options?.onProgress?.({ phase: 'saving' });
355→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
356→
357→    // Save new insight, then delete old prompt_quality insights
358→    saveInsightsToDb([insight]);
359→    deleteSessionInsights(session.id, {
360→      includeOnlyTypes: ['prompt_quality'],
361→      excludeIds: [insight.id],
362→    });
363→
364→    return {
365→      success: true,
366→      insights: [insight],
367→      usage: response.usage ? {
368→        inputTokens: response.usage.inputTokens,
369→        outputTokens: response.usage.outputTokens,
370→      } : undefined,
371→    };
372→  } catch (error) {
373→    if (error instanceof Error && error.name === 'AbortError') {
374→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
375→    }
376→    return {
377→      success: false,
378→      insights: [],
379→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
380→      error_type: 'api_error',
381→    };
382→  }
383→}
