401→/**
402→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
403→ */
404→export async function findRecurringInsights(
405→  insights: Array<{
406→    id: string;
407→    type: string;
408→    title: string;
409→    summary: string;
410→    project_name: string;
411→    session_id: string;
412→  }>
413→): Promise<RecurringInsightResult> {
414→  if (!isLLMConfigured()) {
415→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
416→  }
417→
418→  const candidates = insights
419→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
420→    .slice(0, 200);
421→
422→  if (candidates.length < 2) {
423→    return {
424→      success: false,
425→      groups: [],
426→      updatedCount: 0,
427→      error: 'Need at least 2 non-summary insights to find patterns.',
428→    };
429→  }
430→
431→  try {
432→    const client = createLLMClient();
433→
434→    const insightData = candidates.map(i => ({
435→      id: i.id,
436→      type: i.type === 'technique' ? 'learning' : i.type,
437→      title: i.title,
438→      summary: i.summary.slice(0, 150),
439→      projectName: i.project_name,
440→      sessionId: i.session_id,
441→    }));
442→
443→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
444→
445→RULES:
446→- Only group insights that are genuinely about the same concept/topic
447→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
448→- A group must have at least 2 insights
449→- An insight can only belong to one group
450→- Provide a brief "theme" describing what the group shares
451→- If no recurring patterns exist, return an empty groups array
452→
453→INSIGHTS:
454→${JSON.stringify(insightData, null, 2)}
455→
456→Respond with valid JSON only:
457→{
458→  "groups": [
459→    {
460→      "insightIds": ["insight_abc", "insight_def"],
461→      "theme": "Brief description of the shared concept"
462→    }
463→  ]
464→}`;
465→
466→    const response = await client.chat([
467→      {
468→        role: 'system',
469→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
470→      },
471→      { role: 'user', content: prompt },
472→    ]);
473→
474→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
475→    if (!jsonMatch) {
476→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
477→    }
478→
479→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
480→    const groups = parsed.groups || [];
481→
482→    const validIds = new Set(candidates.map(i => i.id));
483→    const validGroups = groups
484→      .map(g => ({
485→        ...g,
486→        insightIds: g.insightIds.filter(id => validIds.has(id)),
487→      }))
488→      .filter(g => g.insightIds.length >= 2);
489→
490→    if (validGroups.length === 0) {
491→      return {
492→        success: true,
493→        groups: [],
494→        updatedCount: 0,
495→        usage: response.usage
496→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
497→          : undefined,
498→      };
499→    }
500→
501→    // Build bidirectional links
502→    const linkMap = new Map<string, string[]>();
503→    for (const group of validGroups) {
504→      for (const id of group.insightIds) {
505→        const others = group.insightIds.filter(otherId => otherId !== id);
506→        const existing = linkMap.get(id) || [];
507→        linkMap.set(id, [...new Set([...existing, ...others])]);
508→      }
509→    }
510→
511→    // Write links to SQLite
512→    const db = getDb();
513→    const updateLinks = db.prepare(
514→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
515→    );
516→
517→    for (const [insightId, linkedIds] of linkMap.entries()) {
518→      updateLinks.run(JSON.stringify(linkedIds), insightId);
519→    }
520→
521→    return {
522→      success: true,
523→      groups: validGroups,
524→      updatedCount: linkMap.size,
525→      usage: response.usage
526→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
527→        : undefined,
528→    };
529→  } catch (error) {
530→    return {
531→      success: false,
532→      groups: [],
533→      updatedCount: 0,
534→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
535→    };
536→  }
537→}
