539→// --- Internal helpers ---
540→
541→function chunkMessages(
542→  messages: SQLiteMessageRow[],
543→  estimateTokens: (text: string) => number
544→): SQLiteMessageRow[][] {
545→  const chunks: SQLiteMessageRow[][] = [];
546→  let currentChunk: SQLiteMessageRow[] = [];
547→  let currentTokens = 0;
548→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
549→
550→  for (const message of messages) {
551→    let toolResults: Array<{ output?: string }> = [];
552→    try {
553→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
554→    } catch {
555→      toolResults = [];
556→    }
557→
558→    const messageText = [
559→      message.content,
560→      message.thinking?.slice(0, 1000) ?? '',
561→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
562→    ].join(' ');
563→    const messageTokens = estimateTokens(messageText);
564→
565→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
566→      chunks.push(currentChunk);
567→      currentChunk = [];
568→      currentTokens = 0;
569→    }
570→
571→    currentChunk.push(message);
572→    currentTokens += messageTokens;
573→  }
574→
575→  if (currentChunk.length > 0) {
576→    chunks.push(currentChunk);
577→  }
578→
579→  return chunks;
580→}
581→
582→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
583→  if (responses.length === 0) {
584→    return {
585→      summary: { title: 'Analysis failed', content: '', bullets: [] },
586→      decisions: [],
587→      learnings: [],
588→    };
589→  }
590→
591→  if (responses.length === 1) return responses[0];
592→
593→  const merged: AnalysisResponse = {
594→    session_character: responses.find(r => r.session_character)?.session_character,
595→    summary: responses[0].summary,
596→    decisions: [],
597→    learnings: [],
598→  };
599→
600→  for (const response of responses) {
601→    merged.decisions.push(...response.decisions);
602→    merged.learnings.push(...response.learnings);
603→  }
604→
605→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
606→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
607→
608→  return merged;
609→}
610→
611→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
612→  const seen = new Set<string>();
613→  return items.filter((item) => {
614→    const normalized = item.title.toLowerCase().trim();
615→    if (seen.has(normalized)) return false;
616→    seen.add(normalized);
617→    return true;
618→  });
619→}
