621→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
622→  const insights: InsightRow[] = [];
623→  const now = new Date().toISOString();
624→
625→  insights.push({
626→    id: randomUUID(),
627→    session_id: session.id,
628→    project_id: session.project_id,
629→    project_name: session.project_name,
630→    type: 'summary',
631→    title: response.summary.title,
632→    content: response.summary.content,
633→    summary: response.summary.content,
634→    bullets: JSON.stringify(response.summary.bullets),
635→    confidence: 0.9,
636→    source: 'llm',
637→    metadata: response.summary.outcome
638→      ? JSON.stringify({ outcome: response.summary.outcome })
639→      : null,
640→    timestamp: session.ended_at,
641→    created_at: now,
642→    scope: 'session',
643→    analysis_version: ANALYSIS_VERSION,
644→  });
645→
646→  for (const decision of response.decisions) {
647→    const confidence = decision.confidence ?? 85;
648→    if (confidence < 70) continue;
649→
650→    const content = decision.situation && decision.choice
651→      ? `${decision.situation} → ${decision.choice}`
652→      : decision.choice || decision.situation || decision.title;
653→
654→    const altBullets = (decision.alternatives || [])
655→      .filter(a => a && typeof a === 'object' && a.option)
656→      .map(a => `${a.option}: ${a.rejected_because || 'no reason given'}`);
657→
658→    insights.push({
659→      id: randomUUID(),
660→      session_id: session.id,
661→      project_id: session.project_id,
662→      project_name: session.project_name,
663→      type: 'decision',
664→      title: decision.title,
665→      content,
666→      summary: (decision.choice || content).slice(0, 200),
667→      bullets: JSON.stringify(altBullets),
668→      confidence: confidence / 100,
669→      source: 'llm',
670→      metadata: JSON.stringify({
671→        situation: decision.situation,
672→        choice: decision.choice,
673→        reasoning: decision.reasoning,
674→        alternatives: decision.alternatives,
675→        trade_offs: decision.trade_offs,
676→        revisit_when: decision.revisit_when,
677→        evidence: decision.evidence,
678→      }),
679→      timestamp: session.ended_at,
680→      created_at: now,
681→      scope: 'session',
682→      analysis_version: ANALYSIS_VERSION,
683→    });
684→  }
685→
686→  for (const learning of response.learnings) {
687→    const confidence = learning.confidence ?? 80;
688→    if (confidence < 70) continue;
689→
690→    const content = learning.takeaway || learning.title;
691→
692→    insights.push({
693→      id: randomUUID(),
694→      session_id: session.id,
695→      project_id: session.project_id,
696→      project_name: session.project_name,
697→      type: 'learning',
698→      title: learning.title,
699→      content,
700→      summary: content.slice(0, 200),
701→      bullets: JSON.stringify([]),
702→      confidence: confidence / 100,
703→      source: 'llm',
704→      metadata: JSON.stringify({
705→        symptom: learning.symptom,
706→        root_cause: learning.root_cause,
707→        takeaway: learning.takeaway,
708→        applies_when: learning.applies_when,
709→        evidence: learning.evidence,
710→      }),
711→      timestamp: session.ended_at,
712→      created_at: now,
713→      scope: 'session',
714→      analysis_version: ANALYSIS_VERSION,
715→    });
716→  }
717→
718→  return insights;
719→}
