742→    content: response.assessment,
743→    summary: response.assessment,
744→    bullets: JSON.stringify([]),  // takeaways live in metadata.takeaways; bullets expects string[] for other insight types
745→    confidence: 0.85,
746→    source: 'llm',
747→    metadata: JSON.stringify({
748→      efficiency_score: response.efficiency_score,
749→      message_overhead: response.message_overhead,
750→      takeaways: normalizedTakeaways,
751→      findings: normalizedFindings,
752→      dimension_scores: response.dimension_scores,
753→    }),
754→    timestamp: session.ended_at,
755→    created_at: now,
756→    scope: 'session',
757→    analysis_version: ANALYSIS_VERSION,
