232→    trackEvent('analysis_run', pqBaseProperties);
233→    trackEvent('insight_generated', {
234→      type: 'prompt_quality',
235→      count: result.insights.length,
236→    });
237→  }
238→  return c.json(result, result.success ? 200 : 422);
239→});
