241→// GET /api/analysis/prompt-quality/stream?sessionId=X
242→// SSE endpoint — streams progress events during prompt quality analysis.
243→// onProgress is non-async because analyzePromptQuality calls it without await;
244→// stream.writeSSE is fire-and-forget for progress events (non-fatal if missed).
245→app.get('/prompt-quality/stream', async (c) => {
246→  if (!isLLMConfigured()) {
247→    return c.json({
248→      success: false,
249→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
250→    }, 400);
251→  }
252→
253→  const sessionId = c.req.query('sessionId');
254→  if (!sessionId) {
255→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
256→  }
257→
258→  const db = getDb();
259→
260→  const session = db.prepare(`
261→    SELECT id, project_id, project_name, project_path, summary, ended_at
262→    FROM sessions WHERE id = ? AND deleted_at IS NULL
263→  `).get(sessionId) as SessionData | undefined;
264→
265→  if (!session) {
266→    return c.json({ error: 'Session not found' }, 404);
267→  }
268→
269→  const messages = db.prepare(`
270→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
271→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
272→  `).all(sessionId) as SQLiteMessageRow[];
273→
274→  const llmConfig = loadLLMConfig();
275→  return streamSSE(c, async (stream) => {
276→    const pqStreamStart = Date.now();
277→    try {
278→      const abortSignal = c.req.raw.signal;
279→
280→      await stream.writeSSE({
281→        event: 'progress',
282→        data: JSON.stringify({ phase: 'loading_messages', message: 'Loading messages...' }),
283→      });
284→
285→      const result = await analyzePromptQuality(session, messages, {
286→        signal: abortSignal,
287→        onProgress: (progress) => {
288→          const message = progress.phase === 'saving'
289→            ? 'Saving insights...'
290→            : 'Analyzing prompt quality...';
291→          void stream.writeSSE({
292→            event: 'progress',
293→            data: JSON.stringify({ ...progress, message }),
294→          }).catch(() => {});
295→        },
296→      });
297→
298→      const pqStreamBaseProperties = {
299→        type: 'prompt-quality',
300→        llm_provider: llmConfig?.provider,
301→        llm_model: llmConfig?.model,
302→        duration_ms: Date.now() - pqStreamStart,
303→        success: result.success,
304→      };
305→      if (!result.success) {
306→        const pqStreamErrorProperties = {
307→          ...pqStreamBaseProperties,
308→          error_type: result.error_type,
309→          error_message: result.error,
310→          response_preview: result.response_preview,
311→        };
312→        trackEvent('analysis_run', pqStreamErrorProperties);
313→        captureError(new Error(result.error ?? 'prompt_quality stream failed'), pqStreamErrorProperties);
314→        await stream.writeSSE({
315→          event: 'error',
316→          data: JSON.stringify({ error: result.error ?? 'Prompt quality analysis failed' }),
317→        });
318→      } else {
319→        trackEvent('analysis_run', pqStreamBaseProperties);
320→        trackEvent('insight_generated', {
321→          type: 'prompt_quality',
322→          count: result.insights.length,
323→        });
324→        await stream.writeSSE({
325→          event: 'complete',
326→          data: JSON.stringify({
327→            success: true,
328→            insightCount: result.insights.length,
329→            tokenUsage: result.usage,
330→            suggestedTitle: null,
331→          }),
332→        });
333→      }
334→    } catch (err) {
335→      const message = err instanceof Error ? err.message : 'Unknown error';
336→      captureError(err, { type: 'prompt_quality_stream', llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
337→      await stream.writeSSE({
338→        event: 'error',
339→        data: JSON.stringify({ error: message }),
340→      }).catch(() => {});
341→    }
342→  });
343→});
