764→function saveInsightsToDb(insights: InsightRow[]): void {
765→  const db = getDb();
766→  const insert = db.prepare(`
767→    INSERT OR REPLACE INTO insights (
768→      id, session_id, project_id, project_name, type, title, content,
769→      summary, bullets, confidence, source, metadata, timestamp,
770→      created_at, scope, analysis_version
