779→        row.project_id,
780→        row.project_name,
781→        row.type,
782→        row.title,
783→        row.content,
784→        row.summary,
785→        row.bullets,
786→        row.confidence,
787→        row.source,
788→        row.metadata,
789→        row.timestamp,
790→        row.created_at,
791→        row.scope,
792→        row.analysis_version,
