  1→// Friction category normalization using Levenshtein distance.
  2→// Clusters similar free-form friction categories to canonical ones during aggregation.
  3→
  4→import { CANONICAL_FRICTION_CATEGORIES } from './prompts.js';
  5→
  6→// Explicit alias map for clustering emergent category variants.
  7→// Targets don't need to be in CANONICAL_FRICTION_CATEGORIES —
  8→// this clusters semantically-equivalent novel categories together.
  9→// Insert alias lookup runs AFTER exact canonical match but BEFORE Levenshtein,
 10→// so well-known emergent variants are clustered deterministically.
 11→const FRICTION_ALIASES: Record<string, string> = {
 12→  // legacy canonical → new canonical (15→9 taxonomy revision)
 13→  'missing-dependency': 'stale-assumptions',
 14→  'config-drift': 'stale-assumptions',
 15→  'stale-cache': 'stale-assumptions',
 16→  'version-mismatch': 'stale-assumptions',
 17→  'permission-issue': 'stale-assumptions',
 18→  'environment-mismatch': 'stale-assumptions',
 19→  'race-condition': 'wrong-approach',
 20→  'circular-dependency': 'wrong-approach',
 21→  'test-failure': 'wrong-approach',
 22→  'type-error': 'knowledge-gap',
 23→  'api-misunderstanding': 'knowledge-gap',
 24→  // agent orchestration variants → cluster under one emergent name
 25→  'agent-lifecycle-issue': 'agent-orchestration-failure',
 26→  'agent-communication-failure': 'agent-orchestration-failure',
 27→  'agent-communication-breakdown': 'agent-orchestration-failure',
 28→  'agent-lifecycle-management': 'agent-orchestration-failure',
 29→  'agent-shutdown-failure': 'agent-orchestration-failure',
 30→  // rate limit variants → cluster under one emergent name
 31→  'api-rate-limit': 'rate-limit-hit',
 32→  'rate-limiting': 'rate-limit-hit',
 33→  'rate-limited': 'rate-limit-hit',
 34→};
 35→
 36→/** Standard Levenshtein distance between two strings */
 37→function levenshtein(a: string, b: string): number {
 38→  const m = a.length;
 39→  const n = b.length;
 40→  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0) as number[]);
 41→
 42→  for (let i = 0; i <= m; i++) dp[i][0] = i;
 43→  for (let j = 0; j <= n; j++) dp[0][j] = j;
 44→
 45→  for (let i = 1; i <= m; i++) {
 46→    for (let j = 1; j <= n; j++) {
 47→      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
 48→      dp[i][j] = Math.min(
 49→        dp[i - 1][j] + 1,
 50→        dp[i][j - 1] + 1,
 51→        dp[i - 1][j - 1] + cost
 52→      );
 53→    }
 54→  }
 55→
 56→  return dp[m][n];
 57→}
 58→
 59→/**
 60→ * Normalize a friction category to the closest canonical category.
 61→ * Returns the original category if no close match is found.
 62→ *
 63→ * Matching rules (in order):
 64→ * 1. Exact match against canonical list → return as-is
 65→ * 1.5. Explicit alias match → return alias target (may be non-canonical)
 66→ * 2. Levenshtein distance <= 2 → return canonical match
 67→ * 3. Substring match (category contains canonical or vice versa) → return canonical
 68→ * 4. No match → return original (novel category)
 69→ *
 70→ * Note: alias targets in FRICTION_ALIASES bypass the canonical check intentionally.
 71→ * e.g., "agent-orchestration-failure" is not canonical but is a valid cluster target.
 72→ */
 73→export function normalizeFrictionCategory(category: string): string {
 74→  const lower = category.toLowerCase();
 75→
 76→  // 1. Exact match
 77→  for (const canonical of CANONICAL_FRICTION_CATEGORIES) {
 78→    if (lower === canonical) return canonical;
 79→  }
 80→
 81→  // 1.5. Explicit alias match — clusters emergent category variants deterministically.
 82→  // Alias targets bypass further normalization; they are returned as-is even if
 83→  // they are not in CANONICAL_FRICTION_CATEGORIES.
 84→  if (FRICTION_ALIASES[lower]) return FRICTION_ALIASES[lower];
 85→
 86→  // 2. Levenshtein distance <= 2
 87→  let bestMatch: string | null = null;
 88→  let bestDistance = Infinity;
 89→  for (const canonical of CANONICAL_FRICTION_CATEGORIES) {
 90→    const dist = levenshtein(lower, canonical);
 91→    if (dist <= 2 && dist < bestDistance) {
 92→      bestDistance = dist;
 93→      bestMatch = canonical;
 94→    }
 95→  }
 96→  if (bestMatch) return bestMatch;
 97→
 98→  // 3. Substring match — only if the shorter string is a significant portion of the longer
 99→  // to avoid false positives like "type" matching "type-error"
100→  for (const canonical of CANONICAL_FRICTION_CATEGORIES) {
101→    const shorter = lower.length < canonical.length ? lower : canonical;
102→    const longer = lower.length < canonical.length ? canonical : lower;
103→    if (shorter.length >= 5 && shorter.length / longer.length >= 0.5 && longer.includes(shorter)) {
104→      return canonical;
105→    }
106→  }
107→
108→  // 4. No match — novel category
109→  return category;
110→}
