  1→// Shared aggregation logic for facets and reflect routes.
  2→// Extracted to avoid ~150 lines of duplication between the two routes.
  3→
  4→import { getDb } from '@code-insights/cli/db/client';
  5→import { normalizeFrictionCategory } from '../llm/friction-normalize.js';
  6→import { normalizePatternCategory, getPatternCategoryLabel } from '../llm/pattern-normalize.js';
  7→
  8→// ISO week regex: matches YYYY-WNN format (e.g., 2026-W10)
  9→const ISO_WEEK_RE = /^(\d{4})-W(\d{2})$/;
 10→
 11→/**
 12→ * Parse an ISO week string (YYYY-WNN) into UTC Monday/Sunday boundaries.
 13→ * Returns { start: Monday 00:00 UTC, end: next Monday 00:00 UTC } (exclusive end).
 14→ *
 15→ * ISO 8601 week rules: week 1 contains the first Thursday of the year,
 16→ * weeks start on Monday. We use the "Thursday trick": Jan 4 is always
 17→ * in week 1, so we find that Monday, then step to the target week.
 18→ */
 19→export function parseIsoWeek(weekStr: string): { start: Date; end: Date } | null {
 20→  const match = ISO_WEEK_RE.exec(weekStr);
 21→  if (!match) return null;
 22→
 23→  const year = parseInt(match[1], 10);
 24→  const week = parseInt(match[2], 10);
 25→  if (week < 1 || week > 53) return null;
 26→
 27→  // Jan 4 is always in ISO week 1. Find that Monday.
 28→  const jan4 = new Date(Date.UTC(year, 0, 4));
 29→  const jan4Day = jan4.getUTCDay(); // 0=Sun, 1=Mon, ..., 6=Sat
 30→  // Days to Monday of week 1: if Sunday (0), go back 6; else go back (day - 1)
 31→  const daysToMonday = jan4Day === 0 ? 6 : jan4Day - 1;
 32→  const week1Monday = new Date(jan4.getTime() - daysToMonday * 86400000);
 33→
 34→  // Offset to the target week's Monday
 35→  const start = new Date(week1Monday.getTime() + (week - 1) * 7 * 86400000);
 36→  const end = new Date(start.getTime() + 7 * 86400000);
 37→
 38→  return { start, end };
 39→}
 40→
 41→/**
 42→ * Format a Date (representing a Monday) as an ISO week string (YYYY-WNN).
 43→ * Used when generating week inventory from a list of Mondays.
 44→ */
 45→export function formatIsoWeek(monday: Date): string {
 46→  // Find which ISO week number this Monday belongs to.
 47→  // The Monday's Thursday (3 days ahead) determines the year and week.
 48→  const thursday = new Date(monday.getTime() + 3 * 86400000);
 49→  const year = thursday.getUTCFullYear();
 50→
 51→  // Find the Monday of week 1 for this ISO year
 52→  const jan4 = new Date(Date.UTC(year, 0, 4));
 53→  const jan4Day = jan4.getUTCDay();
 54→  const daysToMonday = jan4Day === 0 ? 6 : jan4Day - 1;
 55→  const week1Monday = new Date(jan4.getTime() - daysToMonday * 86400000);
 56→
 57→  const weekNum = Math.round((monday.getTime() - week1Monday.getTime()) / (7 * 86400000)) + 1;
 58→  return `${year}-W${String(weekNum).padStart(2, '0')}`;
 59→}
 60→
 61→export function buildPeriodFilter(period: string): string | null {
 62→  const now = new Date();
 63→  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
 64→  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
 65→  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
 66→  return null; // 'all'
 67→}
 68→
 69→export function buildWhereClause(
 70→  period: string,
 71→  project?: string,
 72→  source?: string
 73→): { where: string; params: (string | number)[] } {
 74→  // Always exclude soft-deleted sessions from aggregations
 75→  const conditions: string[] = ['s.deleted_at IS NULL'];
 76→  const params: (string | number)[] = [];
 77→
 78→  // ISO week period: use precise Monday-to-Monday UTC boundaries
 79→  const isoWeekBounds = parseIsoWeek(period);
 80→  if (isoWeekBounds) {
 81→    conditions.push('s.started_at >= ?');
 82→    params.push(isoWeekBounds.start.toISOString());
 83→    conditions.push('s.started_at < ?');
 84→    params.push(isoWeekBounds.end.toISOString());
 85→  } else {
 86→    const periodStart = buildPeriodFilter(period);
 87→    if (periodStart) {
 88→      conditions.push('s.started_at >= ?');
 89→      params.push(periodStart);
 90→    }
 91→  }
 92→
 93→  if (project) {
 94→    conditions.push('s.project_id = ?');
 95→    params.push(project);
 96→  }
 97→  if (source) {
 98→    conditions.push('s.source_tool = ?');
 99→    params.push(source);
100→  }
101→
102→  return {
103→    where: `WHERE ${conditions.join(' AND ')}`,
104→    params,
105→  };
106→}
