832→/**
833→ * Save extracted facets to the session_facets table.
834→ */
835→function saveFacetsToDb(
836→  sessionId: string,
837→  facets: NonNullable<AnalysisResponse['facets']>,
838→  analysisVersion: string
839→): void {
840→  const db = getDb();
841→
842→  // Normalize pattern categories at write time so stored data is always clean.
843→  // This handles LLM variants (e.g., "task-decomposition" → "structured-planning")
844→  // before they hit the database, keeping aggregation queries simple.
845→  const normalizedPatterns = Array.isArray(facets.effective_patterns)
846→    ? facets.effective_patterns.map(ep => {
847→        if (!ep.category) {
848→          // Should not happen with updated prompts — indicates model ignored category instruction.
849→          // Fall back to 'uncategorized' so these sessions don't trigger the outdated banner.
850→          console.warn('[pattern-monitor] saveFacetsToDb: effective_pattern missing category field, defaulting to uncategorized');
851→        }
852→        return {
853→          ...ep,
854→          category: ep.category ? normalizePatternCategory(ep.category) : 'uncategorized',
855→        };
856→      })
857→    : [];
858→
859→  db.prepare(`
860→    INSERT OR REPLACE INTO session_facets
861→    (session_id, outcome_satisfaction, workflow_pattern, had_course_correction,
862→     course_correction_reason, iteration_count, friction_points, effective_patterns,
863→     analysis_version)
864→    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
865→  `).run(
866→    sessionId,
867→    facets.outcome_satisfaction,
868→    facets.workflow_pattern,
869→    facets.had_course_correction ? 1 : 0,
870→    facets.course_correction_reason,
871→    facets.iteration_count,
872→    JSON.stringify(Array.isArray(facets.friction_points) ? facets.friction_points : []),
873→    JSON.stringify(normalizedPatterns),
874→    analysisVersion
875→  );
876→}
