 99→export async function analyzeSession(
100→  session: SessionData,
101→  messages: SQLiteMessageRow[],
102→  options?: AnalysisOptions
103→): Promise<AnalysisResult> {
104→  if (!isLLMConfigured()) {
105→    return {
106→      success: false,
107→      insights: [],
108→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
109→    };
110→  }
111→
112→  if (messages.length === 0) {
113→    return {
114→      success: false,
115→      insights: [],
116→      error: 'No messages found for this session.',
117→    };
118→  }
119→
120→  try {
121→    const client = createLLMClient();
122→    const formattedMessages = formatMessagesForAnalysis(messages);
123→    const estimatedTokens = client.estimateTokens(formattedMessages);
124→
125→    let analysisResponse: AnalysisResponse;
126→    let totalInputTokens = 0;
127→    let totalOutputTokens = 0;
128→
129→    if (estimatedTokens > MAX_INPUT_TOKENS) {
130→      // Chunk the messages and analyze separately
131→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
132→      const chunkResponses: AnalysisResponse[] = [];
133→      const totalChunks = chunks.length;
134→
135→      for (let i = 0; i < chunks.length; i++) {
136→        const chunk = chunks[i];
137→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
138→
139→        const chunkFormatted = formatMessagesForAnalysis(chunk);
140→        const prompt = generateSessionAnalysisPrompt(
141→          session.project_name,
142→          session.summary,
143→          chunkFormatted
144→        );
145→
146→        const response = await client.chat([
147→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
148→          { role: 'user', content: prompt },
149→        ], { signal: options?.signal });
150→
151→        if (response.usage) {
152→          totalInputTokens += response.usage.inputTokens;
153→          totalOutputTokens += response.usage.outputTokens;
154→        }
155→
156→        const parsed = parseAnalysisResponse(response.content);
157→        if (parsed.success) chunkResponses.push(parsed.data);
158→      }
159→
160→      if (chunkResponses.length === 0) {
161→        return {
162→          success: false,
163→          insights: [],
164→          error: 'All chunks failed to parse LLM response',
165→          error_type: 'json_parse_error',
166→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
167→        };
168→      }
169→
170→      analysisResponse = mergeAnalysisResponses(chunkResponses);
171→
172→      // Chunked sessions: extract facets separately using lightweight prompt
173→      // (facets are holistic — can't be merged across chunks)
174→      if (!analysisResponse.facets) {
175→        try {
176→          const firstMsgs = formatMessagesForAnalysis(messages.slice(0, 20));
177→          const lastMsgs = formatMessagesForAnalysis(messages.slice(-20));
178→          const facetPrompt = generateFacetOnlyPrompt(
179→            session.project_name,
180→            session.summary,
181→            firstMsgs,
182→            lastMsgs
183→          );
184→
185→          const facetResponse = await client.chat([
186→            { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
187→            { role: 'user', content: facetPrompt },
188→          ], { signal: options?.signal });
189→
190→          if (facetResponse.usage) {
191→            totalInputTokens += facetResponse.usage.inputTokens;
192→            totalOutputTokens += facetResponse.usage.outputTokens;
193→          }
194→
195→          const facetJson = extractJsonPayload(facetResponse.content);
196→          if (facetJson) {
197→            try {
198→              analysisResponse.facets = JSON.parse(facetJson);
199→            } catch {
200→              // jsonrepair fallback
201→              try {
202→                analysisResponse.facets = JSON.parse(jsonrepair(facetJson));
203→              } catch {
204→                // Facet extraction failed for chunked session — non-fatal
205→              }
206→            }
207→          }
208→        } catch {
209→          // Facet extraction failed for chunked session — non-fatal, continue
210→        }
211→      }
212→    } else {
213→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
214→      const prompt = generateSessionAnalysisPrompt(
215→        session.project_name,
216→        session.summary,
217→        formattedMessages
218→      );
219→
220→      const response = await client.chat([
221→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
222→        { role: 'user', content: prompt },
223→      ], { signal: options?.signal });
224→
225→      if (response.usage) {
226→        totalInputTokens = response.usage.inputTokens;
227→        totalOutputTokens = response.usage.outputTokens;
228→      }
229→
230→      const parsed = parseAnalysisResponse(response.content);
231→      if (!parsed.success) {
232→        return {
233→          success: false,
234→          insights: [],
235→          error: 'Failed to parse LLM response. Please try again.',
236→          error_type: parsed.error.error_type,
237→          response_length: parsed.error.response_length,
238→          response_preview: parsed.error.response_preview,
239→        };
240→      }
241→
242→      analysisResponse = parsed.data;
243→    }
244→
245→    options?.onProgress?.({ phase: 'saving' });
246→    const insights = convertToInsightRows(analysisResponse, session);
247→
248→    // Save new insights first, then delete old non-prompt-quality insights
249→    // (safe order: if save fails, old data is preserved)
250→    saveInsightsToDb(insights);
251→    deleteSessionInsights(session.id, {
252→      excludeTypes: ['prompt_quality'],
253→      excludeIds: insights.map(i => i.id),
254→    });
255→
256→    // Save facets if extracted
257→    if (analysisResponse.facets) {
258→      saveFacetsToDb(session.id, analysisResponse.facets, ANALYSIS_VERSION);
259→    }
260→
261→    // Update session character if LLM classified it
262→    if (analysisResponse.session_character) {
263→      const db = getDb();
264→      db.prepare('UPDATE sessions SET session_character = ? WHERE id = ?')
265→        .run(analysisResponse.session_character, session.id);
266→    }
267→
268→    return {
269→      success: true,
270→      insights,
271→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
272→    };
273→  } catch (error) {
274→    if (error instanceof Error && error.name === 'AbortError') {
275→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
276→    }
277→    return {
278→      success: false,
279→      insights: [],
280→      error: error instanceof Error ? error.message : 'Analysis failed',
281→      error_type: 'api_error',
282→    };
283→  }
284→}
