878→/**
879→ * Extract facets only for a session that already has insights (backfill).
880→ * Uses lightweight prompt with summary + first/last 20 messages.
881→ */
882→export async function extractFacetsOnly(
883→  session: SessionData,
884→  messages: SQLiteMessageRow[],
885→  options?: { signal?: AbortSignal }
886→): Promise<{ success: boolean; error?: string }> {
887→  if (!isLLMConfigured()) {
888→    return { success: false, error: 'LLM not configured.' };
889→  }
890→
891→  if (messages.length === 0) {
892→    return { success: false, error: 'No messages found.' };
893→  }
894→
895→  try {
896→    const client = createLLMClient();
897→    const firstMsgs = formatMessagesForAnalysis(messages.slice(0, 20));
898→    const lastMsgs = formatMessagesForAnalysis(messages.slice(-20));
899→    const prompt = generateFacetOnlyPrompt(
900→      session.project_name,
901→      session.summary,
902→      firstMsgs,
903→      lastMsgs
904→    );
905→
906→    const response = await client.chat([
907→      { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
908→      { role: 'user', content: prompt },
909→    ], { signal: options?.signal });
910→
911→    const jsonPayload = extractJsonPayload(response.content);
912→    if (!jsonPayload) {
913→      return { success: false, error: 'No JSON in facet response.' };
914→    }
915→
916→    let facets: AnalysisResponse['facets'];
917→    try {
918→      facets = JSON.parse(jsonPayload);
919→    } catch {
920→      facets = JSON.parse(jsonrepair(jsonPayload));
921→    }
922→
923→    if (facets) {
924→      saveFacetsToDb(session.id, facets, ANALYSIS_VERSION);
925→    }
926→
927→    return { success: true };
928→  } catch (error) {
929→    if (error instanceof Error && error.name === 'AbortError') {
930→      return { success: false, error: 'Cancelled' };
931→    }
932→    return {
933→      success: false,
934→      error: error instanceof Error ? error.message : 'Facet extraction failed',
935→    };
936→  }
937→}
