 73→// GET /api/analysis/session/stream?sessionId=X
 74→// SSE endpoint — streams progress events during session analysis.
 75→// onProgress is non-async because analyzeSession calls it without await;
 76→// stream.writeSSE is fire-and-forget for progress events (non-fatal if missed).
 77→app.get('/session/stream', async (c) => {
 78→  if (!isLLMConfigured()) {
 79→    return c.json({
 80→      success: false,
 81→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 82→    }, 400);
 83→  }
 84→
 85→  const sessionId = c.req.query('sessionId');
 86→  if (!sessionId) {
 87→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
 88→  }
 89→
 90→  const db = getDb();
 91→
 92→  const session = db.prepare(`
 93→    SELECT id, project_id, project_name, project_path, summary, ended_at
 94→    FROM sessions WHERE id = ? AND deleted_at IS NULL
 95→  `).get(sessionId) as SessionData | undefined;
 96→
 97→  if (!session) {
 98→    return c.json({ error: 'Session not found' }, 404);
 99→  }
100→
101→  const messages = db.prepare(`
102→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
103→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
104→  `).all(sessionId) as SQLiteMessageRow[];
105→
106→  const llmConfig = loadLLMConfig();
107→  return streamSSE(c, async (stream) => {
108→    const streamStart = Date.now();
109→    try {
110→      const abortSignal = c.req.raw.signal;
111→
112→      await stream.writeSSE({
113→        event: 'progress',
114→        data: JSON.stringify({ phase: 'loading_messages', message: 'Loading messages...' }),
115→      });
116→
117→      const result = await analyzeSession(session, messages, {
118→        signal: abortSignal,
119→        onProgress: (progress) => {
120→          const message = progress.phase === 'saving'
121→            ? 'Saving insights...'
122→            : progress.currentChunk && progress.totalChunks
123→              ? `Analyzing... (${progress.currentChunk} of ${progress.totalChunks})`
124→              : 'Analyzing...';
125→          void stream.writeSSE({
126→            event: 'progress',
127→            data: JSON.stringify({ ...progress, message }),
128→          }).catch(() => {});
129→        },
130→      });
131→
132→      const streamBaseProperties = {
133→        type: 'session',
134→        llm_provider: llmConfig?.provider,
135→        llm_model: llmConfig?.model,
136→        duration_ms: Date.now() - streamStart,
137→        success: result.success,
138→      };
139→      if (!result.success) {
140→        const streamErrorProperties = {
141→          ...streamBaseProperties,
142→          error_type: result.error_type,
143→          error_message: result.error,
144→          response_preview: result.response_preview,
145→        };
146→        trackEvent('analysis_run', streamErrorProperties);
147→        captureError(new Error(result.error ?? 'analysis_run stream failed'), streamErrorProperties);
148→        await stream.writeSSE({
149→          event: 'error',
150→          data: JSON.stringify({ error: result.error ?? 'Analysis failed' }),
151→        });
152→      } else {
153→        trackEvent('analysis_run', streamBaseProperties);
154→        trackEvent('insight_generated', {
155→          type: 'session',
156→          count: result.insights.length,
157→        });
158→        const summaryInsight = result.insights.find(i => i.type === 'summary');
159→        await stream.writeSSE({
160→          event: 'complete',
161→          data: JSON.stringify({
162→            success: true,
163→            insightCount: result.insights.length,
164→            tokenUsage: result.usage,
165→            suggestedTitle: summaryInsight?.title ?? null,
166→          }),
167→        });
168→      }
169→    } catch (err) {
170→      const message = err instanceof Error ? err.message : 'Unknown error';
171→      captureError(err, { type: 'session_stream', llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
172→      await stream.writeSSE({
173→        event: 'error',
174→        data: JSON.stringify({ error: message }),
175→      }).catch(() => {});
176→    }
177→  });
178→});
