  1→/**
  2→ * Analysis context for the embedded dashboard.
  3→ * Consumes SSE streaming endpoints for real-time progress and cancellation.
  4→ * Uses fetch() + ReadableStream (not EventSource) for AbortController support.
  5→ */
  6→import {
  7→  createContext,
  8→  useContext,
  9→  useState,
 10→  useRef,
 11→  useCallback,
 12→  ReactNode,
 13→} from 'react';
 14→import { useQueryClient } from '@tanstack/react-query';
 15→import { getSessionTitle } from '@/lib/utils';
 16→import type { Session } from '@/lib/types';
 17→import { toast } from 'sonner';
 18→import { parseSSEStream } from '@/lib/sse';
 19→
 20→const ANALYSIS_TOAST_ID = 'analysis-toast';
 21→
 22→export interface AnalysisState {
 23→  status: 'idle' | 'analyzing' | 'complete' | 'error';
 24→  sessionId: string | null;
 25→  sessionTitle: string | null;
 26→  type: 'session' | 'prompt_quality';
 27→  progress: {
 28→    phase: 'loading_messages' | 'analyzing' | 'saving';
 29→    currentChunk?: number;
 30→    totalChunks?: number;
 31→    message: string;
 32→  } | null;
 33→  result: {
 34→    success: boolean;
 35→    insightCount?: number;
 36→    tokenUsage?: { inputTokens: number; outputTokens: number };
 37→    suggestedTitle?: string | null;
 38→    error?: string;
 39→  } | null;
 40→}
 41→
 42→interface AnalysisContextValue {
 43→  state: AnalysisState;
 44→  startAnalysis: (session: Session, type: 'session' | 'prompt_quality') => Promise<void>;
 45→  cancelAnalysis: () => void;
 46→  clearResult: () => void;
 47→}
 48→
 49→const IDLE_STATE: AnalysisState = {
 50→  status: 'idle',
 51→  sessionId: null,
 52→  sessionTitle: null,
 53→  type: 'session',
 54→  progress: null,
 55→  result: null,
 56→};
 57→
 58→const AnalysisContext = createContext<AnalysisContextValue>({
 59→  state: IDLE_STATE,
 60→  startAnalysis: async () => {},
 61→  cancelAnalysis: () => {},
 62→  clearResult: () => {},
 63→});
 64→
 65→export function useAnalysis() {
 66→  return useContext(AnalysisContext);
 67→}
 68→
 69→function buildToastMessage(
 70→  sessionTitle: string,
 71→  phase: string,
 72→  currentChunk?: number,
 73→  totalChunks?: number
 74→): string {
 75→  if (phase === 'loading_messages') {
 76→    return `Loading messages for "${sessionTitle}"...`;
 77→  }
 78→  if (phase === 'saving') {
 79→    return `Saving insights for "${sessionTitle}"...`;
 80→  }
 81→  if (currentChunk !== undefined && totalChunks !== undefined) {
 82→    return `Analyzing "${sessionTitle}"... (${currentChunk} of ${totalChunks})`;
 83→  }
 84→  return `Analyzing "${sessionTitle}"...`;
 85→}
 86→
 87→export function AnalysisProvider({ children }: { children: ReactNode }) {
 88→  const [state, setState] = useState<AnalysisState>(IDLE_STATE);
 89→  const queryClient = useQueryClient();
 90→  const abortControllerRef = useRef<AbortController | null>(null);
 91→  const isAnalyzingRef = useRef(false);
 92→
 93→  const cancelAnalysis = useCallback(() => {
 94→    abortControllerRef.current?.abort();
 95→    abortControllerRef.current = null;
 96→    isAnalyzingRef.current = false;
 97→    setState(IDLE_STATE);
 98→    toast.info('Analysis cancelled', { id: ANALYSIS_TOAST_ID, duration: 2000 });
 99→  }, []);
100→
101→  const clearResult = useCallback(() => {
102→    setState(IDLE_STATE);
103→  }, []);
104→
105→  const startAnalysis = useCallback(
106→    async (session: Session, type: 'session' | 'prompt_quality') => {
107→      if (isAnalyzingRef.current) {
108→        toast.warning('Analysis already in progress. Please wait or cancel it first.');
109→        return;
110→      }
111→      isAnalyzingRef.current = true;
112→
113→      const sessionTitle = getSessionTitle(session);
114→      const controller = new AbortController();
115→      abortControllerRef.current = controller;
116→
117→      setState({
118→        status: 'analyzing',
119→        sessionId: session.id,
120→        sessionTitle,
121→        type,
122→        progress: {
123→          phase: 'loading_messages',
124→          message: 'Loading messages...',
125→        },
126→        result: null,
127→      });
128→
129→      toast.loading(`Loading messages for "${sessionTitle}"...`, {
130→        id: ANALYSIS_TOAST_ID,
131→      });
132→
133→      const endpoint = type === 'session'
134→        ? `/api/analysis/session/stream?sessionId=${encodeURIComponent(session.id)}`
135→        : `/api/analysis/prompt-quality/stream?sessionId=${encodeURIComponent(session.id)}`;
136→
137→      try {
138→        const response = await fetch(endpoint, {
139→          signal: controller.signal,
140→        });
141→
142→        if (!response.ok) {
143→          const text = await response.text().catch(() => response.statusText);
144→          throw new Error(`API ${response.status}: ${text}`);
145→        }
146→
147→        if (!response.body) {
148→          throw new Error('No response body for SSE stream');
149→        }
150→
151→        for await (const sseEvent of parseSSEStream(response.body)) {
152→          if (controller.signal.aborted) return;
153→
154→          try {
155→            if (sseEvent.event === 'progress') {
156→              const progress = JSON.parse(sseEvent.data) as {
157→                phase: 'loading_messages' | 'analyzing' | 'saving';
158→                currentChunk?: number;
159→                totalChunks?: number;
160→                message: string;
161→              };
162→              const toastMsg = buildToastMessage(
163→                sessionTitle,
164→                progress.phase,
165→                progress.currentChunk,
166→                progress.totalChunks
167→              );
168→              setState((prev) => ({ ...prev, progress }));
169→              toast.loading(toastMsg, { id: ANALYSIS_TOAST_ID });
170→            } else if (sseEvent.event === 'complete') {
171→              const result = JSON.parse(sseEvent.data) as {
172→                success: boolean;
173→                insightCount: number;
174→                tokenUsage?: { inputTokens: number; outputTokens: number };
175→                suggestedTitle?: string | null;
176→              };
177→
178→              queryClient.invalidateQueries({ queryKey: ['insights'] });
179→              queryClient.invalidateQueries({ queryKey: ['session', session.id] });
180→
181→              const successMsg = `${result.insightCount} insight${result.insightCount !== 1 ? 's' : ''} saved for "${sessionTitle}"`;
182→
183→              setState({
184→                status: 'complete',
185→                sessionId: session.id,
186→                sessionTitle,
187→                type,
188→                progress: null,
189→                result: {
190→                  success: true,
191→                  insightCount: result.insightCount,
192→                  tokenUsage: result.tokenUsage,
193→                  suggestedTitle: result.suggestedTitle,
194→                },
195→              });
196→              toast.success(successMsg, { id: ANALYSIS_TOAST_ID });
197→            } else if (sseEvent.event === 'error') {
198→              const errorData = JSON.parse(sseEvent.data) as { error: string };
199→              setState({
200→                status: 'error',
201→                sessionId: session.id,
202→                sessionTitle,
203→                type,
204→                progress: null,
205→                result: { success: false, error: errorData.error },
206→              });
207→              toast.error(`Analysis failed: ${errorData.error}`, { id: ANALYSIS_TOAST_ID });
208→            }
209→          } catch {
210→            // Malformed SSE event data — skip and continue
211→            continue;
212→          }
213→        }
214→
215→        // Stream ended — if no terminal event was received, treat as unexpected close
216→        if (!controller.signal.aborted) {
217→          setState((prev) => {
218→            if (prev.status === 'analyzing') {
219→              toast.error('Analysis connection closed unexpectedly', { id: ANALYSIS_TOAST_ID });
220→              return {
221→                ...prev,
222→                status: 'error',
223→                progress: null,
224→                result: { success: false, error: 'Connection closed unexpectedly' },
225→              };
226→            }
227→            return prev;
228→          });
229→        }
230→      } catch (error) {
231→        if (controller.signal.aborted) {
232→          return;
233→        }
234→        const errorMsg = error instanceof Error ? error.message : 'Analysis failed';
235→        setState({
236→          status: 'error',
237→          sessionId: session.id,
238→          sessionTitle,
239→          type,
240→          progress: null,
241→          result: { success: false, error: errorMsg },
242→        });
243→        toast.error(`Analysis failed: ${errorMsg}`, { id: ANALYSIS_TOAST_ID });
244→      } finally {
245→        abortControllerRef.current = null;
246→        isAnalyzingRef.current = false;
247→      }
248→    },
249→    [queryClient]
250→  );
251→
252→  return (
253→    <AnalysisContext.Provider value={{ state, startAnalysis, cancelAnalysis, clearResult }}>
254→      {children}
255→    </AnalysisContext.Provider>
256→  );
257→}
