 22→export function BulkAnalyzeButton({ sessions, onComplete }: BulkAnalyzeButtonProps) {
 23→  const [open, setOpen] = useState(false);
 24→  const [analyzing, setAnalyzing] = useState(false);
 25→  const [progress, setProgress] = useState({ completed: 0, total: 0 });
 26→  const [result, setResult] = useState<{
 27→    successful: number;
 28→    failed: number;
 29→    errors: string[];
 30→  } | null>(null);
 31→  const { data: llmConfig } = useLlmConfig();
