104→          </DialogDescription>
105→        </DialogHeader>
106→
107→        <div className="space-y-4 py-4">
108→          {!analyzing && !result && (
109→            <>
110→              <p className="text-sm text-muted-foreground">
111→                This will use your configured LLM provider to analyze each session and generate insights.
112→              </p>
113→              <Button onClick={handleAnalyze} className="w-full gap-2">
114→                <Sparkles className="h-4 w-4" />
115→                Start Analysis
116→              </Button>
117→            </>
118→          )}
119→
120→          {analyzing && (
