582→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
583→  if (responses.length === 0) {
584→    return {
585→      summary: { title: 'Analysis failed', content: '', bullets: [] },
586→      decisions: [],
587→      learnings: [],
588→    };
589→  }
590→
591→  if (responses.length === 1) return responses[0];
592→
593→  const merged: AnalysisResponse = {
594→    session_character: responses.find(r => r.session_character)?.session_character,
595→    summary: responses[0].summary,
596→    decisions: [],
597→    learnings: [],
598→  };
599→
600→  for (const response of responses) {
601→    merged.decisions.push(...response.decisions);
602→    merged.learnings.push(...response.learnings);
603→  }
604→
605→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
606→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
607→
608→  return merged;
609→}
610→
611→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
612→  const seen = new Set<string>();
613→  return items.filter((item) => {
614→    const normalized = item.title.toLowerCase().trim();
615→    if (seen.has(normalized)) return false;
616→    seen.add(normalized);
617→    return true;
618→  });
619→}
