681→      scope: 'session',
682→      analysis_version: ANALYSIS_VERSION,
683→    });
684→  }
685→
686→  for (const learning of response.learnings) {
687→    const confidence = learning.confidence ?? 80;
688→    if (confidence < 70) continue;
689→
690→    const content = learning.takeaway || learning.title;
691→
692→    insights.push({
693→      id: randomUUID(),
694→      session_id: session.id,
695→      project_id: session.project_id,
696→      project_name: session.project_name,
697→      type: 'learning',
698→      title: learning.title,
699→      content,
700→      summary: content.slice(0, 200),
701→      bullets: JSON.stringify([]),
702→      confidence: confidence / 100,
703→      source: 'llm',
704→      metadata: JSON.stringify({
705→        symptom: learning.symptom,
706→        root_cause: learning.root_cause,
707→        takeaway: learning.takeaway,
708→        applies_when: learning.applies_when,
709→        evidence: learning.evidence,
710→      }),
711→      timestamp: session.ended_at,
712→      created_at: now,
713→      scope: 'session',
714→      analysis_version: ANALYSIS_VERSION,
715→    });
716→  }
717→
718→  return insights;
