  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { isLLMConfigured } from '../llm/client.js';
  5→import { extractFacetsOnly } from '../llm/analysis.js';
  6→import type { SQLiteMessageRow, SessionData } from '../llm/analysis.js';
  7→import { buildWhereClause, getAggregatedData } from './shared-aggregation.js';
  8→
  9→const app = new Hono();
 10→
 11→const MAX_BACKFILL_SESSIONS = 200;
 12→
 13→interface FacetRow {
 14→  session_id: string;
 15→  outcome_satisfaction: string;
 16→  workflow_pattern: string | null;
 17→  had_course_correction: number;
 18→  course_correction_reason: string | null;
 19→  iteration_count: number;
 20→  friction_points: string;     // JSON
 21→  effective_patterns: string;  // JSON
 22→  extracted_at: string;
 23→  analysis_version: string;
 24→}
 25→
 26→// GET /api/facets
 27→// Query params: project (project_id), period (7d|30d|90d|all), source (source_tool filter)
 28→// Returns: { facets, missingCount, totalSessions }
 29→app.get('/', (c) => {
 30→  const db = getDb();
 31→  const project = c.req.query('project');
 32→  const period = c.req.query('period') || '30d';
 33→  const source = c.req.query('source');
 34→
 35→  const { where, params } = buildWhereClause(period, project, source);
 36→
 37→  // Total sessions in scope
 38→  const totalRow = db.prepare(
 39→    `SELECT COUNT(*) as count FROM sessions s ${where}`
 40→  ).get(...params) as { count: number };
 41→
 42→  // Sessions with facets — join to sessions so period/project/source filters apply
 43→  const facets = db.prepare(
 44→    `SELECT sf.* FROM session_facets sf
 45→     JOIN sessions s ON sf.session_id = s.id
 46→     ${where}
 47→     ORDER BY s.started_at DESC`
 48→  ).all(...params) as FacetRow[];
 49→
 50→  return c.json({
 51→    facets,
 52→    missingCount: totalRow.count - facets.length,
 53→    totalSessions: totalRow.count,
 54→  });
 55→});
 56→
 57→// GET /api/facets/aggregated
 58→// Returns pre-aggregated friction categories and effective patterns for synthesis.
 59→// Uses the shared getAggregatedData function to avoid duplication with reflect routes.
 60→app.get('/aggregated', (c) => {
 61→  const db = getDb();
 62→  const project = c.req.query('project');
 63→  const period = c.req.query('period') || '30d';
 64→  const source = c.req.query('source');
 65→
 66→  const { where, params } = buildWhereClause(period, project, source);
 67→  const aggregated = getAggregatedData(db, where, params, project, source);
 68→
 69→  return c.json(aggregated);
 70→});
 71→
 72→// GET /api/facets/missing
 73→// Returns session IDs that have insights but no session_facets row.
 74→// Used by CLI `reflect backfill` and dashboard facet status indicators.
 75→app.get('/missing', (c) => {
 76→  const db = getDb();
 77→  const period = c.req.query('period') || 'all';
 78→  const project = c.req.query('project');
 79→  const source = c.req.query('source');
 80→
 81→  // buildWhereClause can't be used here — it generates "WHERE ..." prefix,
 82→  // but this query already needs "WHERE sf.session_id IS NULL".
 83→  // Build conditions inline instead.
 84→  const conditions: string[] = ['sf.session_id IS NULL', 's.deleted_at IS NULL'];
 85→  const params: (string | number)[] = [];
 86→
 87→  if (period !== 'all') {
 88→    const now = new Date();
 89→    const days = period === '7d' ? 7 : period === '30d' ? 30 : period === '90d' ? 90 : 0;
 90→    if (days > 0) {
 91→      conditions.push('s.started_at >= ?');
 92→      params.push(new Date(now.getTime() - days * 86400000).toISOString());
 93→    }
 94→  }
 95→  if (project) {
 96→    conditions.push('s.project_id = ?');
 97→    params.push(project);
 98→  }
 99→  if (source) {
100→    conditions.push('s.source_tool = ?');
101→    params.push(source);
102→  }
103→
104→  const where = `WHERE ${conditions.join(' AND ')}`;
105→
106→  const rows = db.prepare(`
107→    SELECT DISTINCT i.session_id
108→    FROM insights i
109→    JOIN sessions s ON i.session_id = s.id
110→    LEFT JOIN session_facets sf ON i.session_id = sf.session_id
111→    ${where}
112→  `).all(...params) as Array<{ session_id: string }>;
113→
114→  const sessionIds = rows.map(r => r.session_id);
115→  return c.json({ sessionIds, count: sessionIds.length });
116→});
117→
118→// GET /api/facets/outdated
119→// Returns count and sessionIds of session_facets rows where:
120→//   - effective_patterns entries lack a category or driver field, OR
121→//   - friction_points entries lack an attribution field
122→// Accepts period + project to scope to the user's current view — avoids misleading counts
123→// when the user is viewing "last 7 days" but sees outdated sessions from all time.
124→app.get('/outdated', (c) => {
125→  const db = getDb();
126→  const project = c.req.query('project');
127→  const period = c.req.query('period') || '30d';
128→
129→  const { where, params } = buildWhereClause(period, project);
130→
131→  // UNION of two subqueries — each finds session_ids with a specific outdated signal.
132→  // UNION (not UNION ALL) deduplicates sessions that fail both checks.
133→  // The effective_patterns arm uses OR to catch both missing category and missing driver
134→  // in a single scan rather than two separate UNION arms.
135→  const rows = db.prepare(`
136→    SELECT DISTINCT sf.session_id
137→    FROM session_facets sf
138→    JOIN sessions s ON sf.session_id = s.id
139→    CROSS JOIN json_each(sf.effective_patterns) je
140→    ${where}
141→    AND json_array_length(sf.effective_patterns) > 0
142→    AND (json_extract(je.value, '$.category') IS NULL
143→         OR json_extract(je.value, '$.driver') IS NULL)
144→    UNION
145→    SELECT DISTINCT sf.session_id
146→    FROM session_facets sf
147→    JOIN sessions s ON sf.session_id = s.id
148→    CROSS JOIN json_each(sf.friction_points) je
149→    ${where}
150→    AND json_array_length(sf.friction_points) > 0
151→    AND json_extract(je.value, '$.attribution') IS NULL
152→  `).all(...params, ...params) as Array<{ session_id: string }>;
153→
154→  const sessionIds = rows.map(r => r.session_id);
155→  return c.json({ count: sessionIds.length, sessionIds });
156→});
157→
158→// POST /api/facets/backfill
159→// Body: { sessionIds: string[], force?: boolean }
160→// Streams progress as facets are extracted one-by-one for sessions that lack them.
161→// force=true skips the existing-facets guard, allowing re-extraction of outdated rows.
162→// Uses extractFacetsOnly (lightweight prompt: summary + first/last 20 messages).
163→app.post('/backfill', async (c) => {
164→  if (!isLLMConfigured()) {
165→    return c.json({ error: 'LLM not configured.' }, 400);
166→  }
167→
168→  const body = await c.req.json<{ sessionIds?: string[]; force?: boolean }>();
169→  if (!body.sessionIds || !Array.isArray(body.sessionIds) || body.sessionIds.length === 0) {
170→    return c.json({ error: 'sessionIds array required' }, 400);
171→  }
172→  if (body.sessionIds.length > MAX_BACKFILL_SESSIONS) {
173→    return c.json({ error: `Maximum ${MAX_BACKFILL_SESSIONS} sessions per backfill request` }, 400);
174→  }
175→
176→  const db = getDb();
177→
178→  return streamSSE(c, async (stream) => {
179→    const abortSignal = c.req.raw.signal;
180→    let completed = 0;
181→    let failed = 0;
182→    const total = body.sessionIds!.length;
183→
184→    for (const sessionId of body.sessionIds!) {
185→      if (abortSignal.aborted) break;
186→
187→      const session = db.prepare(
188→        `SELECT id, project_id, project_name, project_path, summary, ended_at
189→         FROM sessions WHERE id = ? AND deleted_at IS NULL`
190→      ).get(sessionId) as SessionData | undefined;
191→
192→      if (!session) {
193→        failed++;
194→        await stream.writeSSE({
195→          event: 'progress',
196→          data: JSON.stringify({
197→            completed,
198→            failed,
199→            total,
200→            currentSessionId: sessionId,
201→          }),
202→        });
203→        continue;
204→      }
205→
206→      // Skip sessions that already have facets unless force=true (used when re-processing
207→      // outdated sessions that have stale attribution/driver/category fields).
208→      if (!body.force) {
209→        const existingFacet = db.prepare(
210→          'SELECT 1 FROM session_facets WHERE session_id = ?'
211→        ).get(sessionId);
212→        if (existingFacet) {
213→          completed++;
214→          await stream.writeSSE({
215→            event: 'progress',
216→            data: JSON.stringify({
217→              completed,
218→              failed,
219→              total,
220→              currentSessionId: sessionId,
221→            }),
222→          });
223→          continue;
224→        }
225→      }
226→
227→      // Only load first 20 and last 20 messages for facet extraction
228→      const firstMessages = db.prepare(
229→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
230→         FROM messages WHERE session_id = ? ORDER BY timestamp ASC LIMIT 20`
231→      ).all(sessionId) as SQLiteMessageRow[];
232→
233→      const lastMessages = db.prepare(
234→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
235→         FROM messages WHERE session_id = ? ORDER BY timestamp DESC LIMIT 20`
236→      ).all(sessionId) as SQLiteMessageRow[];
237→
238→      // Merge and deduplicate (for sessions with <= 40 messages, some overlap)
239→      const seenIds = new Set<string>();
240→      const messages: SQLiteMessageRow[] = [];
241→      for (const msg of [...firstMessages, ...lastMessages.reverse()]) {
242→        if (!seenIds.has(msg.id)) {
243→          seenIds.add(msg.id);
244→          messages.push(msg);
245→        }
246→      }
247→
248→      const result = await extractFacetsOnly(session, messages, { signal: abortSignal });
249→      if (result.success) {
250→        completed++;
251→      } else {
252→        failed++;
253→      }
254→
255→      await stream.writeSSE({
256→        event: 'progress',
257→        data: JSON.stringify({
258→          completed,
259→          failed,
260→          total,
261→          currentSessionId: sessionId,
262→          ...(result.success ? {} : { error: result.error }),
263→        }),
264→      });
265→    }
266→
267→    await stream.writeSSE({
268→      event: 'complete',
269→      data: JSON.stringify({ completed, failed, total }),
270→    });
271→  });
272→});
273→
274→export default app;
